export function getWhatsAppLink(product) {
  return `https://wa.me/${WHATSAPP_NUMBER}?text=${encodeURIComponent(product.whatsappMessage)}`
}

export function formatPrice(price) {
  return `₦${price.toLocaleString('en-NG')}`
}
